DATA = EMBEDDED_DATA.filter(r=>r.Company);
filtered = DATA.slice();
initFilters();
updateAll();

function fmt(n,d=2){ if(n===null||n===undefined||isNaN(n)) return '—'; return Number(n).toLocaleString(undefined,{minimumFractionDigits:d,maximumFractionDigits:d}); }

/* ============ ORCHESTRATOR ============ */
function updateAll(){
  // Each panel renders independently — if one fails (e.g. Chart.js didn't load
  // due to a network hiccup or ad-blocker), the rest of the dashboard — including
  // the filters, KPIs, and table — must still update correctly.
  safeRun('renderKPIs', () => renderKPIs(filtered));
  safeRun('renderCharts', () => renderCharts(filtered));
  safeRun('renderHeatGrid', () => renderHeatGrid(filtered));
  safeRun('renderRankList', () => renderRankList(filtered));
  safeRun('renderInsights', () => renderInsights(filtered));
  safeRun('sortAndRender', () => sortAndRender());
}

function safeRun(label, fn){
  try{
    fn();
  } catch(err){
    console.error(`[dashboard] ${label} failed:`, err);
  }
}

/* ============ KPI CARDS ============ */
function renderKPIs(rows){
  if(!rows.length){
    document.getElementById('kpiRow').innerHTML = `<div class="kpi-card"><div class="kpi-lbl">No companies match these filters</div></div>`;
    return;
  }
  const totalSales = rows.reduce((a,r)=>a+(r['Sales ($B)']||0),0);
  const totalProfit = rows.reduce((a,r)=>a+(r['Profit ($B)']||0),0);
  const avgMargin = rows.reduce((a,r)=>a+(r['Profit_Margin_%']||0),0)/rows.length;
  const countries = new Set(rows.map(r=>r.Country)).size;
  const industries = new Set(rows.map(r=>r.Industry)).size;

  const kpis = [
    {icon:'◆', chip:'--chip1', label:'Total Companies', value:rows.length.toLocaleString()},
    {icon:'$', chip:'--chip2', label:'Combined Sales ($B)', value:Math.round(totalSales).toLocaleString()},
    {icon:'▲', chip:'--chip3', label:'Combined Profit ($B)', value:Math.round(totalProfit).toLocaleString()},
    {icon:'%', chip:'--chip4', label:'Avg Profit Margin', value:fmt(avgMargin,1)+'%'},
    {icon:'●', chip:'--chip5', label:'Countries · Industries', value:countries+' · '+industries},
  ];
  document.getElementById('kpiRow').innerHTML = kpis.map(k=>`
    <div class="kpi-card">
      <div class="kpi-top">
        <div class="kpi-icon" style="background:var(${k.chip}); color:var(--accent);">${k.icon}</div>
      </div>
      <div class="kpi-num">${k.value}</div>
      <div class="kpi-lbl">${k.label}</div>
    </div>`).join('');
}

/* ============ HEAT GRID (map substitute) ============ */
function renderHeatGrid(rows){
  const counts = {};
  rows.forEach(r=>{ if(r.Country) counts[r.Country]=(counts[r.Country]||0)+1; });
  const top = Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,18);
  if(!top.length){
    document.getElementById('heatGrid').innerHTML = `<div class="heatcell"><div class="c">No matches</div></div>`;
    return;
  }
  const max = top[0][1];
  document.getElementById('heatGrid').innerHTML = top.map(([c,v])=>{
    const intensity = 0.25 + 0.75*(v/max);
    return `<div class="heatcell" style="background:color-mix(in srgb, var(--accent) ${Math.round(intensity*60)}%, var(--panel-2));">
      <div class="c">${c}</div><div class="v">${v}</div>
    </div>`;
  }).join('');
}

/* ============ TOP 10 LIST ============ */
function renderRankList(rows){
  const top = rows.filter(r=>r['Market Value ($B)']).sort((a,b)=>b['Market Value ($B)']-a['Market Value ($B)']).slice(0,10);
  if(!top.length){
    document.getElementById('rankList').innerHTML = `<li>No matches</li>`;
    return;
  }
  document.getElementById('rankList').innerHTML = top.map((r,i)=>`
    <li><span><span class="n">${i+1}</span>${r.Company}</span><span class="v">$${fmt(r['Market Value ($B)'],0)}B</span></li>
  `).join('');
}

/* ============ INSIGHTS & RECOMMENDATIONS ============ */
function renderInsights(rows){
  const grid = document.getElementById('insightsGrid');
  const tag = document.getElementById('insightsTag');
  tag.textContent = rows.length===DATA.length ? 'ALL 2000 COMPANIES' : `${rows.length} COMPANIES MATCHED`;

  if(rows.length < 3){
    grid.innerHTML = `<div class="insight-card"><div class="i-headline">Not enough data</div><div class="i-body">Broaden your filters to generate insights — at least a few companies are needed for meaningful patterns.</div></div>`;
    return;
  }

  const withMV = rows.filter(r=>r['Market Value ($B)']);
  const totalMV = withMV.reduce((a,r)=>a+r['Market Value ($B)'],0);
  const top10MV = withMV.slice().sort((a,b)=>b['Market Value ($B)']-a['Market Value ($B)']).slice(0,10)
    .reduce((a,r)=>a+r['Market Value ($B)'],0);
  const concentration = totalMV ? (top10MV/totalMV*100) : 0;

  const countryCounts = {};
  rows.forEach(r=>{ if(r.Country) countryCounts[r.Country]=(countryCounts[r.Country]||0)+1; });
  const [leadCountry, leadCountryCount] = Object.entries(countryCounts).sort((a,b)=>b[1]-a[1])[0] || ['—',0];
  const leadCountryShare = rows.length ? (leadCountryCount/rows.length*100) : 0;

  const withMargin = rows.filter(r=>r['Profit_Margin_%']!==null && !isNaN(r['Profit_Margin_%']));
  const thinMargin = withMargin.filter(r=>r['Profit_Margin_%']<5).length;
  const thinMarginShare = withMargin.length ? (thinMargin/withMargin.length*100) : 0;
  const strongMargin = withMargin.filter(r=>r['Profit_Margin_%']>20).length;
  const strongMarginShare = withMargin.length ? (strongMargin/withMargin.length*100) : 0;

  // industry aggregates (need >=3 companies to avoid noise)
  const indAgg = {};
  rows.forEach(r=>{
    if(!r.Industry) return;
    indAgg[r.Industry] = indAgg[r.Industry] || {marginSum:0, marginN:0, roaSum:0, roaN:0, count:0};
    indAgg[r.Industry].count++;
    if(r['Profit_Margin_%']!==null && !isNaN(r['Profit_Margin_%'])){ indAgg[r.Industry].marginSum+=r['Profit_Margin_%']; indAgg[r.Industry].marginN++; }
    if(r['ROA_%']!==null && !isNaN(r['ROA_%'])){ indAgg[r.Industry].roaSum+=r['ROA_%']; indAgg[r.Industry].roaN++; }
  });
  const indEligible = Object.entries(indAgg).filter(([,v])=>v.count>=3);
  let bestMarginInd = null, bestROAInd = null;
  if(indEligible.length){
    bestMarginInd = indEligible.map(([k,v])=>[k, v.marginN?v.marginSum/v.marginN:0]).sort((a,b)=>b[1]-a[1])[0];
    bestROAInd = indEligible.map(([k,v])=>[k, v.roaN?v.roaSum/v.roaN:0]).sort((a,b)=>b[1]-a[1])[0];
  }

  const avgMargin = withMargin.length ? withMargin.reduce((a,r)=>a+r['Profit_Margin_%'],0)/withMargin.length : 0;

  const cards = [];

  // Insight 1: Market concentration
  cards.push({
    kicker:'Market Structure', stat: fmt(concentration,0)+'%',
    headline:'Top 10 companies hold outsized market value',
    body:`The 10 largest companies by market value account for ${fmt(concentration,0)}% of the combined market value across the ${rows.length} companies shown.`
  });

  // Insight 2: Geographic concentration
  cards.push({
    kicker:'Geographic Footprint', stat: fmt(leadCountryShare,0)+'%',
    headline:`${leadCountry} leads by company count`,
    body:`${leadCountry} contributes ${leadCountryCount} of ${rows.length} companies (${fmt(leadCountryShare,0)}%) in the current view.`
  });

  // Insight 3: Margin distribution
  cards.push({
    kicker:'Profitability Spread', stat: fmt(strongMarginShare,0)+'%',
    headline:'Split between high and thin margins',
    body:`${fmt(strongMarginShare,0)}% of companies post margins above 20%, while ${fmt(thinMarginShare,0)}% operate below 5% — average margin sits at ${fmt(avgMargin,1)}%.`
  });

  // Recommendation 1: concentration risk
  cards.push({
    rec:true, kicker:'Recommendation',
    headline: concentration>40 ? 'Diversify beyond the top-heavy leaders' : 'Concentration risk is moderate',
    body: concentration>40
      ? `With ${fmt(concentration,0)}% of market value sitting in just 10 names, a portfolio weighted to this view is exposed to single-company swings. Consider balancing exposure with mid-tier companies (ranks 100–500) for diversification.`
      : `Market value is reasonably spread across companies in this view — concentration risk is lower than typical for a top-heavy index.`
  });

  // Recommendation 2: geography
  cards.push({
    rec:true, kicker:'Recommendation',
    headline: leadCountryShare>50 ? `Reduce reliance on ${leadCountry}` : 'Geographic mix looks balanced',
    body: leadCountryShare>50
      ? `${leadCountry} represents over half the companies shown. If building a diversified view, cross-check the Country filter against Japan, China, and EU markets to avoid single-region bias.`
      : `No single country dominates this view — a reasonable spread of geographic exposure across the filtered companies.`
  });

  // Recommendation 3: profitability leaders
  if(bestMarginInd && bestROAInd){
    cards.push({
      rec:true, kicker:'Recommendation',
      headline:`Watch ${bestMarginInd[0]} and ${bestROAInd[0]}`,
      body:`${bestMarginInd[0]} shows the strongest average profit margin (${fmt(bestMarginInd[1],1)}%), while ${bestROAInd[0]} leads on capital efficiency (avg ROA ${fmt(bestROAInd[1],1)}%). Both are worth a closer look in the Company Explorer below.`
    });
  } else {
    cards.push({
      rec:true, kicker:'Recommendation',
      headline:'Narrow the filter for industry-level insight',
      body:`Select a specific industry or broaden the current filter to surface which sectors lead on margin and capital efficiency.`
    });
  }

  grid.innerHTML = cards.map(c=>`
    <div class="insight-card ${c.rec?'rec':''}">
      <div class="i-kicker">${c.kicker}</div>
      ${c.stat ? `<div class="i-stat">${c.stat}</div>` : ''}
      <div class="i-headline">${c.headline}</div>
      <div class="i-body">${c.body}</div>
    </div>
  `).join('');
}

/* ============ FILTERS ============ */
function initFilters(){
  const countries = [...new Set(DATA.map(r=>r.Country))].filter(Boolean).sort();
  const industries = [...new Set(DATA.map(r=>r.Industry))].filter(Boolean).sort();
  const cSel = document.getElementById('countryFilter');
  const iSel = document.getElementById('industryFilter');
  countries.forEach(c=>{ const o=document.createElement('option'); o.value=c; o.textContent=c; cSel.appendChild(o); });
  industries.forEach(i=>{ const o=document.createElement('option'); o.value=i; o.textContent=i; iSel.appendChild(o); });

  document.getElementById('searchInput').addEventListener('input', applyFilters);
  cSel.addEventListener('change', applyFilters);
  iSel.addEventListener('change', applyFilters);
  document.getElementById('rankFilter').addEventListener('change', applyFilters);
  document.getElementById('marginFilter').addEventListener('change', applyFilters);
  document.getElementById('resetFilters').addEventListener('click', ()=>{
    document.getElementById('searchInput').value='';
    cSel.value=''; iSel.value=''; document.getElementById('rankFilter').value=''; document.getElementById('marginFilter').value='';
    applyFilters();
  });

  document.querySelectorAll('th[data-key]').forEach(th=>{
    th.addEventListener('click', ()=>{
      const key = th.dataset.key;
      if(sortKey===key){ sortDir*=-1; } else { sortKey=key; sortDir = key==='Rank'?1:-1; }
      document.querySelectorAll('th[data-key]').forEach(t=>t.classList.remove('sorted'));
      th.classList.add('sorted');
      sortAndRender();
    });
  });
}

function applyFilters(){
  const q = document.getElementById('searchInput').value.toLowerCase();
  const c = document.getElementById('countryFilter').value;
  const i = document.getElementById('industryFilter').value;
  const rk = document.getElementById('rankFilter').value;
  const mg = document.getElementById('marginFilter').value;

  filtered = DATA.filter(r=>{
    if(q && !(r.Company||'').toLowerCase().includes(q)) return false;
    if(c && r.Country!==c) return false;
    if(i && r.Industry!==i) return false;
    if(rk){
      const [lo,hi] = rk.split('-').map(Number);
      if(!(r.Rank>lo && r.Rank<=hi)) return false;
    }
    if(mg){
      const m = r['Profit_Margin_%'];
      if(mg==='high' && !(m>20)) return false;
      if(mg==='mid' && !(m>=5 && m<=20)) return false;
      if(mg==='low' && !(m<5)) return false;
    }
    return true;
  });
  updateAll();
}

function sortAndRender(){
  filtered.sort((a,b)=>{
    let av=a[sortKey], bv=b[sortKey];
    if(typeof av==='string'){ av=(av||'').toLowerCase(); bv=(bv||'').toLowerCase(); return av<bv?-1*sortDir:av>bv?1*sortDir:0; }
    av = av===null||av===undefined||isNaN(av) ? -Infinity : av;
    bv = bv===null||bv===undefined||isNaN(bv) ? -Infinity : bv;
    return (av-bv)*sortDir;
  });
  renderTable();
}

function renderTable(){
  const rows = filtered.slice(0,60);
  document.getElementById('tableBody').innerHTML = rows.map(r=>`
    <tr>
      <td>#${r.Rank}</td>
      <td class="name-cell">${r.Company}</td>
      <td>${r.Country||'—'}</td>
      <td>${r.Industry||'—'}</td>
      <td>${fmt(r['Sales ($B)'])}</td>
      <td>${fmt(r['Profit ($B)'])}</td>
      <td>${r['Market Value ($B)']!==null && !isNaN(r['Market Value ($B)']) ? fmt(r['Market Value ($B)']) : '—'}</td>
      <td class="${r['Profit_Margin_%']>=0?'pos':'neg'}">${fmt(r['Profit_Margin_%'],1)}%</td>
      <td class="${r['ROA_%']>=0?'pos':'neg'}">${fmt(r['ROA_%'],1)}%</td>
    </tr>`).join('');
  document.getElementById('rowCount').textContent = filtered.length + ' ROWS';
}

/* ============ CHARTS ============ */
function themeColors(){
  const cs = getComputedStyle(document.body);
  return {
    text: cs.getPropertyValue('--text').trim(),
    dim: cs.getPropertyValue('--dim').trim(),
    accent: cs.getPropertyValue('--accent').trim(),
    grid: cs.getPropertyValue('--grid').trim(),
    pos: cs.getPropertyValue('--pos').trim(),
    neg: cs.getPropertyValue('--neg').trim(),
  };
}

function renderCharts(rows){
  if(typeof Chart === 'undefined'){
    // Chart.js failed to load (network issue, ad-blocker, offline first load).
    // Show a readable fallback in each chart panel instead of leaving blank canvases.
    document.querySelectorAll('.panel-chart').forEach(panel=>{
      panel.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--dim);font-size:11px;text-align:center;padding:0 16px;">Charts couldn\'t load (Chart.js unavailable). KPIs, filters, and the table below still work.</div>';
    });
    return;
  }
  const c = themeColors();
  Chart.defaults.font.family = "'IBM Plex Sans', sans-serif";
  Chart.defaults.font.size = 10.5;
  Chart.defaults.color = c.dim;
  Object.values(charts).forEach(ch=>ch && ch.destroy());
  if(!rows.length) return;

  /* Trend: Market value sum by rank bracket */
  const brackets = {};
  rows.forEach(r=>{
    const b = Math.floor((r.Rank-1)/100)*100;
    brackets[b] = (brackets[b]||0) + (r['Market Value ($B)']||0);
  });
  const bKeys = Object.keys(brackets).map(Number).sort((a,b)=>a-b);
  charts.trend = new Chart(document.getElementById('trendChart'), {
    type:'line',
    data:{
      labels: bKeys.map(k=>`${k+1}-${k+100}`),
      datasets:[{
        data: bKeys.map(k=>Math.round(brackets[k])),
        borderColor:c.accent, backgroundColor:c.accent+'33',
        fill:true, tension:.35, pointRadius:0, borderWidth:2
      }]
    },
    options:{
      responsive:true, maintainAspectRatio:false,
      plugins:{ legend:{display:false}, tooltip:{callbacks:{label:(ctx)=>`$${ctx.raw.toLocaleString()}B`}} },
      scales:{
        x:{ grid:{display:false}, ticks:{color:c.dim, maxRotation:0, autoSkip:true, maxTicksLimit:8} },
        y:{ grid:{color:c.grid}, ticks:{color:c.dim} }
      }
    }
  });

  /* Donut: industry mix top 6 */
  const indCounts = {};
  rows.forEach(r=>{ if(r.Industry) indCounts[r.Industry]=(indCounts[r.Industry]||0)+1; });
  const topInd6 = Object.entries(indCounts).sort((a,b)=>b[1]-a[1]).slice(0,6);
  const palette = [c.accent, c.pos, c.neg, '#6C8EBF', '#B08BD9', '#5DA3A8'];
  charts.donut = new Chart(document.getElementById('donutChart'), {
    type:'doughnut',
    data:{ labels: topInd6.map(d=>d[0]), datasets:[{ data: topInd6.map(d=>d[1]), backgroundColor:palette, borderWidth:2, borderColor:'transparent' }] },
    options:{
      responsive:true, maintainAspectRatio:false, cutout:'62%',
      plugins:{ legend:{ position:'bottom', labels:{ boxWidth:8, font:{size:9.5}, color:c.dim } } }
    }
  });

  /* Industry bar */
  const topInd10 = Object.entries(indCounts).sort((a,b)=>b[1]-a[1]).slice(0,10);
  charts.industry = new Chart(document.getElementById('industryChart'), {
    type:'bar',
    data:{ labels: topInd10.map(d=>d[0]), datasets:[{ data: topInd10.map(d=>d[1]), backgroundColor:c.accent, borderRadius:2 }] },
    options:{
      indexAxis:'y', responsive:true, maintainAspectRatio:false,
      plugins:{ legend:{display:false} },
      scales:{ x:{ grid:{color:c.grid}, ticks:{color:c.dim} }, y:{ grid:{display:false}, ticks:{color:c.text, font:{size:9.5}} } }
    }
  });

  /* Margin histogram */
  const bins = [0,5,10,20,30,50,100,10000];
  const binLabels = ['0-5%','5-10%','10-20%','20-30%','30-50%','50-100%','100%+'];
  const binCounts = new Array(binLabels.length).fill(0);
  rows.forEach(r=>{
    const m = r['Profit_Margin_%'];
    if(m===null||isNaN(m)) return;
    for(let i=0;i<bins.length-1;i++){ if(m>=bins[i] && m<bins[i+1]){ binCounts[i]++; break; } }
  });
  charts.marginHist = new Chart(document.getElementById('marginHistChart'), {
    type:'bar',
    data:{ labels: binLabels, datasets:[{ data: binCounts, backgroundColor:c.pos, borderRadius:2 }] },
    options:{
      responsive:true, maintainAspectRatio:false,
      plugins:{ legend:{display:false} },
      scales:{ x:{ grid:{display:false}, ticks:{color:c.dim, font:{size:9}} }, y:{ grid:{color:c.grid}, ticks:{color:c.dim} } }
    }
  });

  /* ROA by rank tier */
  const roaBrackets = {};
  const roaCounts = {};
  rows.forEach(r=>{
    const b = Math.floor((r.Rank-1)/250)*250;
    if(r['ROA_%']===null || isNaN(r['ROA_%'])) return;
    roaBrackets[b] = (roaBrackets[b]||0) + r['ROA_%'];
    roaCounts[b] = (roaCounts[b]||0) + 1;
  });
  const rKeys = Object.keys(roaBrackets).map(Number).sort((a,b)=>a-b);
  charts.roa = new Chart(document.getElementById('roaChart'), {
    type:'bar',
    data:{
      labels: rKeys.map(k=>`${k+1}-${k+250}`),
      datasets:[{ data: rKeys.map(k=>(roaBrackets[k]/roaCounts[k]).toFixed(1)), backgroundColor:c.neg, borderRadius:2 }]
    },
    options:{
      responsive:true, maintainAspectRatio:false,
      plugins:{ legend:{display:false}, tooltip:{callbacks:{label:(ctx)=>`${ctx.raw}%`}} },
      scales:{
        x:{ grid:{display:false}, ticks:{color:c.dim, maxRotation:45, minRotation:45, font:{size:9}} },
        y:{ grid:{color:c.grid}, ticks:{color:c.dim, callback:(v)=>v+'%'} }
      }
    }
  });
}
